// We declare this function MUST return an Int
fun addNumbers(a: Int, b: Int): Int {
    val sum = a + b
    return sum // Here we send the answer back
}

fun main() {
    // We catch the returned value in a variable
    val result = addNumbers(10, 5)
    println("The result is $result")
}

// The long way
fun multiply(a: Int, b: Int): Int {
    return a * b
}

// The Kotlin expert way!
fun multiplyFast(a: Int, b: Int) = a * b
